const config = $('Config Reporte').first().json;
const timezone = config.timezone || 'America/Santiago';
const now = new Date();

const closedValues = new Set(String(config.closed_status_values || 'closed,resolved,rejected,cancelled,cerrado,resuelto,rechazado')
  .split(',')
  .map(v => v.trim().toLowerCase())
  .filter(Boolean));

const company = String(config.Company || config.company || 'TecnoComp').trim();
const itopOrganization = String(config.itop_organization || '').trim();
const subjectBase = String(config.email_subject || 'Reporte ITSM - tickets abiertos pendientes por agente').trim();
const sendOnlyWithAgentEmail = String(config.send_only_with_agent_email ?? 'true').toLowerCase() !== 'false';
const fallbackAgentEmail = String(config.fallback_agent_email || '').trim();

function isEnabledFlag(value, defaultValue = true) {
  if (value === undefined || value === null || value === '') return defaultValue;
  if (typeof value === 'boolean') return value;
  const normalized = String(value).trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'y', 'on', 'enabled'].includes(normalized);
}

const includeRequirements = isEnabledFlag(config.include_requirements, true);
const includeIncidents = isEnabledFlag(config.include_incidents, true);
const includeChanges = isEnabledFlag(config.include_changes, true);
const includeProblems = isEnabledFlag(config.include_problems, true);

const enabledTicketTypes = new Set();
if (includeRequirements) enabledTicketTypes.add('requirement');
if (includeIncidents) enabledTicketTypes.add('incident');
if (includeChanges) enabledTicketTypes.add('change');
if (includeProblems) enabledTicketTypes.add('problem');

function normalizeTicketKind(value, fields = {}) {
  const rawValues = [
    value,
    getField(fields, ['finalclass', 'class', 'class_friendlyname', 'ticket_class', 'ticket_type', 'type', 'request_type', 'request_type_friendlyname'], ''),
    getField(fields, ['ref', 'reference', 'friendlyname'], '')
  ].map(v => String(v || '').trim()).filter(Boolean);

  const raw = rawValues.join(' ').toLowerCase();

  if (raw.includes('userrequest') || raw.includes('user request') || raw.includes('request') || raw.includes('requerimiento') || raw.includes('requisito') || raw.includes('solicitud')) {
    return { key: 'requirement', label: 'Requerimiento' };
  }
  if (raw.includes('incident') || raw.includes('incidente') || raw.includes('incidencia')) {
    return { key: 'incident', label: 'Incidente' };
  }
  if (raw.includes('change') || raw.includes('cambio')) {
    return { key: 'change', label: 'Cambio' };
  }
  if (raw.includes('problem') || raw.includes('problema')) {
    return { key: 'problem', label: 'Problema' };
  }

  return { key: 'unknown', label: rawValues[0] || 'No identificado' };
}

function enabledTicketTypeText() {
  const labels = [];
  if (includeRequirements) labels.push('Requerimientos');
  if (includeIncidents) labels.push('Incidentes');
  if (includeChanges) labels.push('Cambios');
  if (includeProblems) labels.push('Problemas');
  return labels.length ? labels.join(', ') : 'Sin tipos habilitados';
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function stripHtml(value) {
  return String(value ?? '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#039;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function rawField(obj, names) {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return undefined;
}

function entryDateValue(entry, fallbackKey = '') {
  if (!entry || typeof entry !== 'object') return fallbackKey;
  return entry.date || entry.created || entry.created_at || entry.creation_date || entry.timestamp || entry.time || fallbackKey || '';
}

function entryAuthorValue(entry) {
  if (!entry || typeof entry !== 'object') return '';
  return entry.user_id_friendlyname || entry.user_friendlyname || entry.user_name || entry.user_login || entry.author || entry.author_friendlyname || '';
}

function normalizeLogText(value, fallbackKey = '') {
  if (value === undefined || value === null || value === '') return '';

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = stripHtml(value);
    return text && text !== '[object Object]' ? text : '';
  }

  if (Array.isArray(value)) {
    const normalized = value
      .map((entry, index) => ({
        date: entryDateValue(entry, String(index).padStart(6, '0')),
        text: normalizeLogText(entry, String(index).padStart(6, '0')),
      }))
      .filter(e => e.text);
    if (!normalized.length) return '';
    normalized.sort((a, b) => String(a.date).localeCompare(String(b.date)));
    return normalized[normalized.length - 1].text;
  }

  if (typeof value === 'object') {
    const direct = rawField(value, [
      'message', 'html', 'text', 'body', 'content', 'comment', 'note',
      'last_comment', 'last_note', 'entry', 'value', 'description'
    ]);

    if (direct !== undefined && direct !== value) {
      const text = normalizeLogText(direct, fallbackKey);
      if (text) {
        const date = entryDateValue(value, fallbackKey);
        const author = entryAuthorValue(value);
        const prefix = [date, author].map(v => stripHtml(v)).filter(Boolean).join(' - ');
        return prefix ? `${prefix}: ${text}` : text;
      }
    }

    const collection = value.entries || value.items || value.log || value.logs || value.records || value.data;
    if (collection && collection !== value) {
      const entries = Array.isArray(collection)
        ? collection.map((v, i) => [String(i).padStart(6, '0'), v])
        : Object.entries(collection);
      const normalized = entries
        .map(([key, entry]) => ({ date: entryDateValue(entry, key), text: normalizeLogText(entry, key) }))
        .filter(e => e.text);
      if (!normalized.length) return '';
      normalized.sort((a, b) => String(a.date).localeCompare(String(b.date)));
      return normalized[normalized.length - 1].text;
    }

    // Fallback para estructuras de iTop expuestas como objetos planos o respuestas parciales.
    const nestedEntries = Object.entries(value)
      .filter(([, val]) => val && typeof val === 'object')
      .map(([key, val]) => ({ date: entryDateValue(val, key), text: normalizeLogText(val, key) }))
      .filter(e => e.text);
    if (nestedEntries.length) {
      nestedEntries.sort((a, b) => String(a.date).localeCompare(String(b.date)));
      return nestedEntries[nestedEntries.length - 1].text;
    }

    const leafTexts = [];
    const ignored = new Set(['id', 'key', 'code', 'class', 'finalclass', 'type', 'attribute', 'attcode', 'att_code']);
    for (const [key, val] of Object.entries(value)) {
      if (ignored.has(String(key).toLowerCase())) continue;
      if (typeof val === 'string' || typeof val === 'number' || typeof val === 'boolean') {
        const text = stripHtml(val);
        if (text && text !== '[object Object]') leafTexts.push(text);
      }
    }
    const unique = [...new Set(leafTexts)].filter(t => t.length > 1);
    return unique.slice(-3).join(' / ');
  }

  return '';
}

function getLastReadableNote(fields) {
  const candidates = [
    rawField(fields, ['last_comment', 'last_note', 'last_public_log', 'last_private_log', 'last_update_reason', 'last_change']),
    rawField(fields, ['public_log', 'private_log', 'user_satisfaction', 'caselog', 'work_log', 'history']),
    rawField(fields, ['description'])
  ];

  for (const candidate of candidates) {
    const text = normalizeLogText(candidate);
    if (text) return text;
  }
  return '-';
}

function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      }
      continue;
    }
    if (Array.isArray(j)) {
      rows.push(...j);
      continue;
    }
    rows.push(j);
  }
  return rows;
}

function parseDate(value) {
  if (!value || value === '-') return null;
  if (value instanceof Date) return Number.isNaN(value.getTime()) ? null : value;
  const raw = String(value).trim();
  if (!raw) return null;
  const normalized = raw.includes('T') ? raw : raw.replace(' ', 'T');
  const d = new Date(normalized);
  return Number.isNaN(d.getTime()) ? null : d;
}

function fmtDateTime(value) {
  const d = parseDate(value);
  if (!d) return '-';
  return d.toLocaleString('es-CL', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function diffHours(from, to = now) {
  const d = parseDate(from);
  if (!d) return 0;
  return Math.max(0, Math.floor((to.getTime() - d.getTime()) / 36e5));
}

function formatDurationFromHours(hours) {
  const h = Math.max(0, Math.floor(Number(hours || 0)));
  const days = Math.floor(h / 24);
  const rem = h % 24;
  if (days <= 0) return `${rem}h`;
  if (rem === 0) return `${days}d`;
  return `${days}d ${rem}h`;
}

function isBlank(value) {
  const v = String(value ?? '').trim();
  return !v || v === '-' || v.toLowerCase() === 'null' || v.toLowerCase() === 'undefined' || v.toLowerCase() === 'n/a';
}

function isClosed(status) {
  const s = String(status || '').trim().toLowerCase();
  return closedValues.has(s);
}

function collectLogEntries(value, collector = []) {
  if (value === undefined || value === null || value === '') return collector;

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = stripHtml(value);
    if (text && text !== '[object Object]') collector.push({ date: '', author: '', text });
    return collector;
  }

  if (Array.isArray(value)) {
    value.forEach(v => collectLogEntries(v, collector));
    return collector;
  }

  if (typeof value === 'object') {
    const date = value.date || value.created || value.created_at || value.creation_date || value.timestamp || value.time || value.modification_date || '';
    const author = value.user_id_friendlyname || value.user_friendlyname || value.user_name || value.user_login || value.author || value.author_friendlyname || '';

    const direct = rawField(value, [
      'message', 'html', 'text', 'body', 'content', 'comment', 'note',
      'entry', 'value', 'description'
    ]);

    if (direct !== undefined && direct !== value) {
      const text = stripHtml(direct);
      if (text && text !== '[object Object]') collector.push({ date, author, text });
    }

    const collection = value.entries || value.items || value.log || value.logs || value.records || value.data;
    if (collection && collection !== value) collectLogEntries(collection, collector);
  }

  return collector;
}

function getLastLog(fields) {
  const candidates = [
    rawField(fields, ['last_comment', 'last_note', 'last_public_log', 'last_private_log', 'last_update_reason', 'last_change']),
    rawField(fields, ['public_log', 'private_log', 'user_satisfaction', 'caselog', 'work_log', 'history'])
  ];

  const entries = [];
  for (const candidate of candidates) collectLogEntries(candidate, entries);

  const valid = entries.filter(e => e.text);
  if (!valid.length) return { text: '-', date: null };

  valid.sort((a, b) => {
    const da = parseDate(a.date)?.getTime() || 0;
    const db = parseDate(b.date)?.getTime() || 0;
    return da - db;
  });

  const last = valid[valid.length - 1];
  const prefix = [last.date ? fmtDateTime(last.date) : '', stripHtml(last.author)].filter(Boolean).join(' - ');
  return {
    text: prefix ? `${prefix}: ${last.text}` : last.text,
    date: parseDate(last.date)
  };
}

function detectLastUpdate(fields, createdAt) {
  const explicitUpdate = getField(fields, [
    'last_update',
    'last_update_date',
    'last_modification_date',
    'last_modified',
    'modification_date',
    'date_mod',
    'updated_at',
    'last_activity',
    'last_activity_date'
  ], '');

  const explicitUpdateDate = parseDate(explicitUpdate);
  const lastLog = getLastLog(fields);
  const logDate = lastLog.date;

  const updateCandidates = [explicitUpdateDate, logDate].filter(Boolean);
  updateCandidates.sort((a, b) => b.getTime() - a.getTime());

  return {
    date: updateCandidates[0] || createdAt || null,
    source: updateCandidates[0] ? 'update' : 'creation_fallback',
    note: lastLog.text || '-'
  };
}

function getSlaInfo(fields) {
  const raw = [
    getField(fields, ['tto_escalation_deadline', 'ttr_escalation_deadline', 'resolution_deadline'], ''),
    getField(fields, ['tto_escalation_flag', 'ttr_escalation_flag', 'sla_status', 'sla', 'slas'], '')
  ].filter(Boolean).join(' ');

  const s = raw.toLowerCase();
  const breached = ['breach', 'breached', 'vencido', 'expired', 'late', 'rojo', 'red'].some(v => s.includes(v));
  return { text: raw || '-', breached };
}

function normalizeStatus(value) {
  const raw = String(value || '').trim();
  const s = raw.toLowerCase();
  const map = {
    ongoing: 'En curso',
    assigned: 'Asignado',
    new: 'Nuevo',
    pending: 'Pendiente',
    waiting_for_approval: 'Esperando aprobación',
    waiting_for_customer: 'Esperando solicitante',
    escalated_tto: 'Escalado TTO',
    escalated_ttr: 'Escalado TTR',
    resolved: 'Resuelto',
    closed: 'Cerrado',
    rejected: 'Rechazado',
    cancelled: 'Cancelado'
  };
  return map[s] || raw || '-';
}

function severity(ticket) {
  if (ticket.slaBreached || ticket.ageDays > 14) return 'Crítico';
  if (ticket.ageDays >= 7) return 'Alto';
  return 'Seguimiento';
}

function severityBadge(ticket) {
  const s = severity(ticket);
  if (s === 'Crítico') return '<span class="badge badge-red">Crítico</span>';
  if (s === 'Alto') return '<span class="badge badge-orange">Alto</span>';
  return '<span class="badge badge-yellow">Seguimiento</span>';
}

function td(value, align = 'left') {
  return `<td align="${align}" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${value}</td>`;
}

function th(text, align = 'left') {
  return `<th align="${align}" style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:${align}; padding:8px 7px; border-bottom:1px solid #dbe3ec; white-space:nowrap;">${escapeHtml(text)}</th>`;
}

function ticketRow(ticket) {
  const note = ticket.lastNote && ticket.lastNote !== '-' ? ticket.lastNote : 'Sin anotación legible desde la respuesta de iTop';
  return `<tr>
    ${td(severityBadge(ticket))}
    ${td(`<strong>${escapeHtml(ticket.ref)}</strong>`)}
    ${td(`<strong>${escapeHtml(ticket.title)}</strong>`)}
    ${td(escapeHtml(ticket.caller))}
    ${td(escapeHtml(fmtDateTime(ticket.createdAt)))}
    ${td(escapeHtml(fmtDateTime(ticket.lastUpdateAt)))}
    ${td(escapeHtml(formatDurationFromHours(ticket.ageHours)))}
    ${td(ticket.slaBreached ? '<span class="badge badge-red">Vencido</span>' : escapeHtml(ticket.slaText || '-'))}
    ${td(`<span class="wrap">${escapeHtml(note).slice(0, 500)}</span>`)}
  </tr>`;
}

function renderTicketTable(tickets) {
  if (!tickets.length) {
    return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec; margin-bottom:20px;"><tr><td style="padding:14px; font-size:13px; color:#64748b;">No existen tickets abiertos asignados al agente.</td></tr></table>`;
  }

  const rows = tickets.map(ticketRow).join('');
  return `<div class="table-scroll" style="width:100%; overflow-x:auto;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="data-table" style="width:100%; border:1px solid #dbe3ec;">
      <thead><tr>
        ${th('Crit.')}${th('Referencia')}${th('Título / asunto')}${th('Solicitante')}${th('Creación')}${th('Último update')}${th('Tiempo abierto')}${th('SLA')}${th('Última anotación / cambio registrado')}
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>
  </div>`;
}

function renderTicketTypeSection(title, tickets) {
  const sorted = [...tickets].sort((a, b) => (a.createdAt?.getTime() || 0) - (b.createdAt?.getTime() || 0));
  return `<div style="font-size:15px; line-height:21px; color:#111827; font-weight:bold; margin:16px 0 8px 0;">${escapeHtml(title)} <span style="color:#64748b; font-weight:normal;">(${sorted.length})</span></div>${renderTicketTable(sorted)}`;
}

function renderTicketsByType(tickets) {
  const sections = [
    { key: 'requirement', title: 'Requerimientos' },
    { key: 'incident', title: 'Incidentes' },
    { key: 'change', title: 'Cambios' },
    { key: 'problem', title: 'Problemas' },
  ];

  const blocks = sections
    .map(section => {
      const list = tickets.filter(ticket => ticket.ticketType === section.key);
      if (!list.length) return '';
      return renderTicketTypeSection(section.title, list);
    })
    .filter(Boolean);

  if (!blocks.length) return renderTicketTable([]);
  return blocks.join('');
}

function normalizeEmail(value) {
  const text = String(value ?? '').trim();
  const match = text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return match ? match[0].toLowerCase() : '';
}

const userRows = (() => {
  try {
    return flattenInput($('iTop - Usuarios Locales con Persona').all());
  } catch (error) {
    return [];
  }
})();

const agentEmailIndex = new Map();

function addAgentEmailIndex(key, email) {
  const k = String(key ?? '').trim();
  const e = normalizeEmail(email);
  if (!k || !e) return;
  agentEmailIndex.set(k.toLowerCase(), e);
}

function indexAgentRecord(row) {
  const f = row.fields || row;

  const email = normalizeEmail(getField(f, [
    'email',
    'email_address',
    'mail',
    'notify_email',
    'business_email',
    'p.email',
    'p_email',
    'person_email',
    'contact_email',
    'contactid_email',
    'contact_id_email',
    'login'
  ], ''));
  if (!email) return;

  const rawKeys = [
    row.key,
    getField(f, ['id'], ''),
    getField(f, ['login'], ''),
    getField(f, ['friendlyname', 'name', 'display_name', 'full_name'], ''),
    getField(f, ['email', 'email_address', 'mail', 'p.email', 'p_email', 'person_email', 'contact_email'], ''),
    getField(f, ['contactid', 'contact_id', 'contactid_id', 'contact_id_id', 'p.id', 'p_id', 'person_id'], ''),
    getField(f, ['contactid_friendlyname', 'contact_id_friendlyname', 'contact_friendlyname', 'person_id_friendlyname', 'p.friendlyname', 'p_friendlyname', 'person_friendlyname'], '')
  ];

  const contactObject = rawField(f, ['contactid', 'contact_id', 'contact', 'person_id', 'person']);
  if (contactObject && typeof contactObject === 'object') {
    const cf = contactObject.fields || contactObject;
    rawKeys.push(
      contactObject.key,
      getField(cf, ['id'], ''),
      getField(cf, ['friendlyname', 'name', 'display_name', 'full_name'], ''),
      getField(cf, ['email', 'email_address', 'mail'], '')
    );
  }

  const rowKey = String(row.key || '').trim();
  const idFromKey = rowKey.includes('::') ? rowKey.split('::').pop() : '';
  if (idFromKey) rawKeys.push(idFromKey, `UserLocal::${idFromKey}`, `User::${idFromKey}`);

  const contactId = String(getField(f, ['contactid', 'contact_id', 'contactid_id', 'contact_id_id', 'p.id', 'p_id', 'person_id'], '') || '').trim();
  if (contactId) rawKeys.push(contactId, `Person::${contactId}`, `Contact::${contactId}`);

  const personFriendly = String(getField(f, ['p.friendlyname', 'p_friendlyname', 'person_friendlyname', 'contactid_friendlyname', 'contact_id_friendlyname'], '') || '').trim();
  if (personFriendly) rawKeys.push(personFriendly);

  for (const key of rawKeys) addAgentEmailIndex(key, email);
}
for (const user of userRows) indexAgentRecord(user);

function lookupAgentEmail(value) {
  if (value === undefined || value === null || value === '') return '';

  const directEmail = normalizeEmail(value);
  if (directEmail) return directEmail;

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const key = String(value).trim().toLowerCase();
    return agentEmailIndex.get(key) || '';
  }

  if (typeof value === 'object') {
    const f = value.fields || value;
    const email = normalizeEmail(getField(f, ['email', 'email_address', 'mail', 'p.email', 'p_email', 'person_email', 'contact_email', 'login'], ''));
    if (email) return email;

    const candidates = [
      value.key,
      getField(f, ['id'], ''),
      getField(f, ['login'], ''),
      getField(f, ['contactid', 'contact_id', 'contactid_id', 'contact_id_id', 'person_id', 'user_id'], ''),
      getField(f, ['contactid_friendlyname', 'contact_id_friendlyname', 'contact_friendlyname', 'person_id_friendlyname'], ''),
      getField(f, ['friendlyname', 'name', 'display_name', 'full_name', 'p.friendlyname', 'p_friendlyname', 'person_friendlyname'], '')
    ];

    for (const candidate of candidates) {
      const key = String(candidate ?? '').trim().toLowerCase();
      if (key && agentEmailIndex.has(key)) return agentEmailIndex.get(key);
    }
  }

  return '';
}

function getAgentEmail(fields) {
  const direct = getField(fields, [
    'agent_id_email',
    'agent_email',
    'assignee_id_email',
    'assignee_email',
    'owner_id_email',
    'owner_email',
    'agent_id_obsolescence_flag_email',
    'agent_id_friendlyname_email',
    'agent_email_address',
    'agent_id_contact_email',
    'agent_id_email_address',
    'agent_id_person_email',
    'email'
  ], '');

  let email = normalizeEmail(direct);
  if (email) return email;

  const lookupCandidates = [
    rawField(fields, ['agent_id']),
    rawField(fields, ['agent']),
    rawField(fields, ['assignee_id']),
    rawField(fields, ['assignee']),
    rawField(fields, ['owner_id']),
    rawField(fields, ['owner']),
    getField(fields, ['agent_id', 'assignee_id', 'owner_id'], ''),
    getField(fields, ['agent_id_friendlyname', 'agent_name', 'assignee_id_friendlyname', 'owner_id_friendlyname'], '')
  ];

  for (const candidate of lookupCandidates) {
    email = lookupAgentEmail(candidate);
    if (email) return email;
  }

  return '';
}

const rows = flattenInput($input.all());

const mappedTickets = rows.map((row) => {
  const f = row.fields || row;
  const statusRaw = getField(f, ['operational_status', 'operational_status_friendlyname', 'status', 'status_friendlyname'], '');
  const createdRaw = getField(f, ['start_date', 'creation_date', 'created_at', 'date', 'opened_at'], '');
  const createdAt = parseDate(createdRaw);
  const lastUpdate = detectLastUpdate(f, createdAt);
  const lastReadableNote = getLastReadableNote(f);
  const ageHours = diffHours(createdAt, now);
  const sla = getSlaInfo(f);
  const ref = getField(f, ['ref', 'reference', 'ticket_ref', 'friendlyname'], row.key || '-');
  const agent = getField(f, ['agent_id_friendlyname', 'agent_name', 'assignee_id_friendlyname', 'team_id_friendlyname', 'owner_id_friendlyname'], 'Sin agente asignado');
  const agentEmail = getAgentEmail(f);
  const ticketKind = normalizeTicketKind(getField(f, ['finalclass', 'class', 'class_friendlyname', 'ticket_class', 'ticket_type', 'type'], ''), f);

  return {
    ref,
    title: stripHtml(getField(f, ['title', 'description', 'name', 'friendlyname'], '-')),
    ticketType: ticketKind.key,
    ticketTypeLabel: ticketKind.label,
    statusRaw,
    statusLabel: normalizeStatus(statusRaw),
    caller: getField(f, ['caller_id_friendlyname', 'customer_id_friendlyname', 'requestor_id_friendlyname', 'person_id_friendlyname'], '-'),
    agent,
    agentEmail: agentEmail || fallbackAgentEmail,
    createdAt,
    lastUpdateAt: lastUpdate.date,
    lastUpdateSource: lastUpdate.source,
    lastNote: lastReadableNote && lastReadableNote !== '-' ? lastReadableNote : lastUpdate.note,
    ageHours,
    ageDays: Math.floor(ageHours / 24),
    slaText: sla.text,
    slaBreached: sla.breached
  };
});

// Evita duplicidad por respuestas repetidas del nodo iTop o joins internos.
// La referencia del ticket es la llave operativa más estable para este reporte.
const uniqueTicketsByRef = new Map();
for (const ticket of mappedTickets) {
  const key = String(ticket.ref || '').trim().toLowerCase() || `${String(ticket.title || '').trim().toLowerCase()}|${String(ticket.agent || '').trim().toLowerCase()}|${String(ticket.createdAt?.toISOString?.() || '').trim()}`;
  if (!uniqueTicketsByRef.has(key)) {
    uniqueTicketsByRef.set(key, ticket);
    continue;
  }

  const current = uniqueTicketsByRef.get(key);
  const currentHasNote = current.lastNote && current.lastNote !== '-';
  const ticketHasNote = ticket.lastNote && ticket.lastNote !== '-';
  if (!currentHasNote && ticketHasNote) uniqueTicketsByRef.set(key, ticket);
}

const tickets = Array.from(uniqueTicketsByRef.values())
.filter(t => !isClosed(t.statusRaw))
.filter(t => enabledTicketTypes.has(t.ticketType))
.filter(t => !sendOnlyWithAgentEmail || !isBlank(t.agentEmail))
.sort((a, b) => (a.createdAt?.getTime() || 0) - (b.createdAt?.getTime() || 0));

const groups = new Map();

for (const ticket of tickets) {
  const key = ticket.agentEmail || fallbackAgentEmail || '';
  if (!key) continue;
  if (!groups.has(key)) {
    groups.set(key, {
      agentEmail: key,
      agentName: ticket.agent || 'Sin agente asignado',
      tickets: []
    });
  }
  groups.get(key).tickets.push(ticket);
}

const generatedAt = now.toLocaleString('es-CL', {
  timeZone: timezone,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit'
});

const generatedAtFile = new Date()
  .toISOString()
  .replace(/[:.]/g, '-')
  .replace('T', '_')
  .slice(0, 19);

const output = [];

for (const group of groups.values()) {
  const list = [...group.tickets].sort((a, b) => (a.createdAt?.getTime() || 0) - (b.createdAt?.getTime() || 0));
  const olderThan14Count = list.filter(t => t.ageDays > 14).length;
  const slaBreachedCount = list.filter(t => t.slaBreached).length;
  const criticalCount = list.filter(t => severity(t) === 'Crítico').length;
  const requirementCount = list.filter(t => t.ticketType === 'requirement').length;
  const incidentCount = list.filter(t => t.ticketType === 'incident').length;
  const changeCount = list.filter(t => t.ticketType === 'change').length;
  const problemCount = list.filter(t => t.ticketType === 'problem').length;
  const typeStatsText = `Requerimientos: ${requirementCount} · Incidentes: ${incidentCount} · Cambios: ${changeCount} · Problemas: ${problemCount}`;
  const oldestTicket = list[0] ? `${list[0].ref} · ${formatDurationFromHours(list[0].ageHours)}` : '-';

  const csvHeaders = [
    'Referencia',
    'Tipo',
    'Titulo',
    'Solicitante',
    'Agente',
    'Email agente',
    'Creacion',
    'Ultimo update',
    'Tiempo abierto',
    'SLA',
    'SLA vencido',
    'Ultima anotacion o cambio'
  ];

  const csvRows = list.map(ticket => [
    ticket.ref,
    ticket.ticketTypeLabel,
    ticket.title,
    ticket.caller,
    ticket.agent,
    ticket.agentEmail,
    fmtDateTime(ticket.createdAt),
    fmtDateTime(ticket.lastUpdateAt),
    formatDurationFromHours(ticket.ageHours),
    ticket.slaText,
    ticket.slaBreached ? 'Si' : 'No',
    ticket.lastNote
  ]);

  const csvContent = '\uFEFF' + [
    csvHeaders.map(csvEscape).join(';'),
    ...csvRows.map(row => row.map(csvEscape).join(';'))
  ].join('\r\n');

  const safeAgent = String(group.agentName || 'agente')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9_-]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 60) || 'agente';

  const emailSubject = itopOrganization
    ? `${subjectBase} - ${itopOrganization} - ${group.agentName}`
    : `${subjectBase} - ${group.agentName}`;

  output.push({
    json: {
      email_from: config.email_from,
      email_to: group.agentEmail,
      email_cc: config.email_cc || '',
      email_bcc: config.email_bcc || '',
      email_subject: emailSubject,
      company,
      Company: company,
      itop_organization: itopOrganization || '-',
      itop_url: config.itop_url || '#',
      generated_at: generatedAt,
      enabled_ticket_types: enabledTicketTypeText(),
      include_requirements: String(includeRequirements),
      include_incidents: String(includeIncidents),
      include_changes: String(includeChanges),
      include_problems: String(includeProblems),
      lookup_records: String(userRows.length),
      indexed_agent_emails: String(agentEmailIndex.size),
      agent_name: group.agentName,
      agent_email: group.agentEmail,
      total_open: String(list.length),
      older_than_14_count: String(olderThan14Count),
      sla_breached_count: String(slaBreachedCount),
      critical_count: String(criticalCount),
      requirement_count: String(requirementCount),
      incident_count: String(incidentCount),
      change_count: String(changeCount),
      problem_count: String(problemCount),
      type_stats_text: typeStatsText,
      oldest_ticket: oldestTicket,
      ticket_rows_html: renderTicketsByType(list),
      csv_filename: `tickets_abiertos_${safeAgent}_${generatedAtFile}.csv`
    },
    binary: {
      csv: {
        data: Buffer.from(csvContent, 'utf8').toString('base64'),
        mimeType: 'text/csv',
        fileName: `tickets_abiertos_${safeAgent}_${generatedAtFile}.csv`
      }
    }
  });
}

return output;

